const Q_PHYSICS_2005=[{"id": "objective>Physics>2005>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pair of physical quantities consisting of vectors only are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">displacement and torque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">momentum and power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceleration and speed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity and distance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Displacement and torque are both vector quantities. A vector quantity is a quantity that has both magnitude and direction. Displacement is the shortest distance from the initial to the final position of a point. It has both magnitude (the distance) and direction (from initial to final position). Torque, also known as moment of force, is the rotational equivalent of linear force. It also has both magnitude (the force) and direction (the direction of rotation).</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2005>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A motorcyclist traveling at 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>starts to apply his brakes when he is 50m from the traffic light that had just turned red. <br/> If he reached the traffic light, his decceleration is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Initial velocity, u = 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Distance, s = 50m <br/> Final velocity, v = 0 <br/> deceleration, a = ? <br/> Recall: <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 2as <br/> 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 900 - 2(a)(50) <br/> 900 = 100a <br/> a = 9 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2005>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is projected from a height of 80m  above the ground with a velocity of 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at an  angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to the horizontal. The time of flight is <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2005/img3.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2usin&#952;<hr size=\"1\" />g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 × 40 × sin30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span><hr size=\"1\" />10</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />10</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4s</td></tr></table></div></div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2005>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the figure above, the coefficient of static friction is 0.5. If the tension in the string  is  T, the acceleration of the system in motion is  <br/> [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2005/pis1.png\" style=\"position:relative;max-width:100%;\"/> <br/> For the 6kg mass <br/> W > T <br/> W - T = ma <br/> mg - T = ma <br/> 60 - T = 6a <br/> T = 60 - 6a ------------------ (1) <br/> For the 3kg mass, <br/> T = mg = 30 ----------------- (2) <br/> Substitute for T = 30N in (i) <br/> 30 = 60-6a <br/> -30 = -6a <br/> a = 5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "FRICTION"}, {"id": "objective>Physics>2005>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 200N acts between two objects at a certain distance apart. The value of the force when the distance is halved is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">800N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2005/img5.png\" style=\"position:relative;max-width:100%;\"/> <br/> The force of attraction = 200N <br/> From Newton's law of universal gravitation <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(</td><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">200(</td><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)<hr size=\"1\" />4</td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 800N </div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2005>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  If the system above is in equilibrium, the tension in the string Q is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If we have masses connected in this manner <br/>  <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>g <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = (m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)g <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> ∴ In the diagram given, the tension in the rope Q = 4 + 5 = 9N</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2005>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The value of F in the figure above when in equilibrium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">27N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2005/k49.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10<hr size=\"1\" />sin150°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />sin90°</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />0.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20N</td></tr></table></div> </div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2005>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the figure above,the work done by the force of 100N inclined at an angle of 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to the object dragged horizontally to a distance of 8m is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">800J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2005/pis4.png\" style=\"position:relative;max-width:100%;\"/> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 100cos60° = 50N <br/> Distance, x = 8m <br/> Recall: W = F × x <br/> W = 50N × 8m = 400J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2005>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an ideal wheel and axle system, R stands for the radius of the wheel and r is the radius of the axle. <br/> The mechanical advantage is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">r</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">R</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">R</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">r</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">(<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">R</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">r</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">(<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">r</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">R</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that, an ideal wheel and axle system has an efficiency of 100% <br/> M.A = V.R <br/> Recall: For a wheel and axle <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V.R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<hr size=\"1\" />r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<hr size=\"1\" />r</td></tr></table></div></div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2005>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An elastic material has length of 36cm when a load of 40N is hung on it and a length of 45cm  when a load of 60N is hung on it. <br/> The original length of the string is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: From Hooke's Law <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> e = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> Based on this question <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40<hr size=\"1\" />36 - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />45 - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">40<hr size=\"1\" />36 - x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />45 - x</td></tr></table></div> <br/> 4(45 - x) = 6(36 - x) <br/> 180 - 4x = 216 - 6x <br/> 2x = 36 <br/> x = 18cm</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2005>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two liquids L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> are contained in a U-tube.The height and the density of L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> are 8cm and 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> respectively. <br/> If the density of L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is 800 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>,its height measured from the same level is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> P = ρgh <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />h</td></tr></table></div> <br/> ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 8cm × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 800 × h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 10cm</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2005>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 36kg falls through a viscous liquid which offers a drag force of 260N on the body. The upthrust on the body at terminal velocity is  <br/> [g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">310N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">620N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Weight of body = 36 x 10 = 360N. <br/> Drag force, V = 260N <br/> At terminal velocity, <br/> W - V - U = 0 <br/> U = W - V <br/> Upthrust = 360N – 260N  <br/> = 100N</div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>2005>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 3m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>volume of liquid W of density 200kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> is mixed with another liquid of volume 7m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and density 150 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. <br/> The density of the mixture is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">350 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">265 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">165 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Density</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">mixture</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> Also, recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">density</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">mixture</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200 × 3 + 150 × 7<hr size=\"1\" />7 + 3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">600 + 1050<hr size=\"1\" />10</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1650<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">165</td><td style=\"text-align:center;\">kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div></div>", "topic": "LIQUIDS AT REST : DENSITY OF SOLID AND LIQUIDS"}, {"id": "objective>Physics>2005>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Reproducibility  <br/> II. Sensitivity   <br/> III. High thermal capacity   <br/>  <br/> IV. High accuracy  <br/> The qualities of a good thermometer include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A good thermometer should have the qualities of reproducibility, sensitivity, and high accuracy. Reproducibility means that the thermometer should give the same reading for the same temperature each time it is used. Sensitivity refers to the ability of the thermometer to detect small changes in temperature. High accuracy means that the thermometer's readings should be very close to the actual temperature. High thermal capacity is not a desirable quality for a thermometer because it would mean that the thermometer would take a long time to reach thermal equilibrium with the system whose temperature is being measured, thus slowing down the measurement process.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2005>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When very hot water is poured into two identical thin and thick glass tumblers in equal volumes, the thick one cracks because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glass is a good conductor of heat.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the uneven expansion of glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glass is a crystal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the even expansion of glass</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thick glass bottles crack when hot water is poured into them because of the uneven expansion of glass.</div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2005>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J of heat is required to boil off completely 2kg of a certain liquid. Neglecting heat loss to the surroundings, the latent heat of vaporization of  <br/> the liquid is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given; <br/> Quantity of heat energy, Q = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J <br/> Mass of liquid, m = 2kg <br/> Latent heat of vaporization, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = ? <br/> Recall: Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = mL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> <br/> 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> = 2 × L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = 0.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2005>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process whereby a liquid turns spontaneously into vapour is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boiling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relegation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process whereby a liquid turns spontaneously into vapour is called evaporation. This is a type of vaporization of a liquid that occurs from the surface of a liquid into a gaseous phase that is not saturated with the evaporating substance. It can occur when the partial pressure of the evaporating substance in the air is less than the equilibrium vapor pressure.</div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2005>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the temperature difference between the wet and dry bulbs of a hygrometer is high, this indicates that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the relative humidity is high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the relative humidity is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is about to rain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is plenty of sunshine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the temperature difference between the wet and dry bulbs of a hygrometer is high, this indicates the relative humidity is low, i.e high dryness.</div>", "topic": "VAPOURS : WET AND DRY BULB HYGROMETERS"}, {"id": "objective>Physics>2005>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process whereby the molecules of different substances move randomly is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capillarity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface tension</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process whereby the molecules of different substances move randomly is called diffusion. Diffusion is the net movement of anything (for example, atoms, ions, molecules) from a region of higher concentration to a region of lower concentration. Diffusion is driven by a gradient in concentration.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2005>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Melting  <br/> II. Boiling  <br/> III. Refraction   <br/> IV.  Conduction   <br/> Which  combination of the above is evident of the molecular nature of matter?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The evidence of molecular nature of  melter include; melting, boiling and conduction. i.e. I, II and IV only.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2005>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity of sound in air will be doubled if its absolute temperature is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">halved</div>", "<div style=\"font-family:Cambria;font-size:17px;\">doubled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quadrupled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> V α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> V = K&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> The velocity of sound will be doubled if the absolute temperature is quadrupled.</div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>2005>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Marching soldiers crossing a suspension bridge are usually advised to break their steps to avoid damaging the bridge owing to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">resonance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">swinging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vibration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oscillation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marching soldiers crossing a suspension bridge are usually advised to break their steps to avoid damaging the bridge owing to resonance.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : RESONANCE"}, {"id": "objective>Physics>2005>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sharpness of the boundary of the shadow of an object is determined  by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nature of the object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opacity of the object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rays of light passing through the object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensity of light striking the object</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sharpness of the boundary of the shadow of an object is determined by the intensity of light striking the object. <br/> N.B: Depending on the intensity of light striking the object, there are two types of shadow, i.e umbra and penubra.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2005>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A real image three times the size of an object is formed 24cm from a converging  mirror. <br/> What is the focal length of the mirror?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">N.B: A converging mirror is a concave mirror <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">-------------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> V = 3U ----------------- * * <br/> V = 24cm <br/> U = 8cm <br/> ∴ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />8</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />24</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3 + 1<hr size=\"1\" />24</td></tr></table></div> <br/> 24 = 4f <br/> f = 6cm <br/> </div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : USE OF THE MIRROR FORMULA"}, {"id": "objective>Physics>2005>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The figure above shows a plot of angles of deviation through a glass prism when light is incident at θ degrees on the prism. <br/>  The incident angle that produces the minimum deviation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">35<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The incident angle that produces the minimum deviation is 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>.</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2005>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A thin converging lens has a power of 4.0 diopters.  <br/>  Determine its focal length.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.03m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.00m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Power, P = 4.0D <br/> focal length, f = ? <br/> Recall: <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />f</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />f</td></tr></table></div> <br/> f = 0.25m</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2005>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Satellite communication network makes use of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sound wave</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radio wave</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infra-red rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">visible light</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Satellite communication networks make use of radio waves. Radio waves are a type of electromagnetic wave that is used in communication because they can travel long distances and through various mediums. Sound waves, infra-red rays, and visible light are not typically used in satellite communication.</div>", "topic": "ELECTROMAGNETIC SPECTRUM"}, {"id": "objective>Physics>2005>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the distance between two point charges is increased by a factor of four, the magnitude of the electrostatic force between them will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 times its former value</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> of its formal value</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span> of its formal value</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">16</span> of its formal value</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> From Coulomb's Law: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">kq<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> -------------------- (i) <br/> If the distance is increased by a factor of 4, <br/> i.e r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> Equation (1) become  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(4r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> × 16r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />`16</td></tr></table></div> <br/> </div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2005>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electric field intensity in a place where a charge of 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>C experiences a force of 0.4N is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Force, F = 0.4N <br/> Charge, q = 0.4N <br/> Charge, q = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>C <br/> Electric Field Intensity, E = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />q</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.4<hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2005>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The figure above shows three capacitors, 2µF, 3µF and 6µF connected in series. If the p.d. across the system is 12V, the p.d.across the 6µF capacitor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3+2+1<hr size=\"1\" />6</td></tr></table></div> <br/> 6 = 6C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> <br/> 6 = 6C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 1.0μF <br/> Note that when capacitors are arranged in series, they have the same charge <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 1.0μF × 12 <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 12μC <br/> p.d across the 6μF capacitor is  <br/> Q = CV <br/> 12μC = 6μF × V <br/> V = 2v</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2005>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car battery rated 45AH is charged with a charger whose rating  is 2.5A. <br/> How long will it take to charge the battery fully?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25 hrs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 hrs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 hrs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 hrs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> * Battery rating (charge), Q = 45AH = 45 × 3600 = 162000C <br/> * Current, I = 2.5A <br/> * Time, t = Unknown <br/> Recall, Q = It <br/> 162000 = 2.5 × t <br/> t = 400 × 162 <br/> t = 64800 seconds  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">64,800<hr size=\"1\" />3600</td><td style=\"text-align:center;\">hours</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> t = 18 hours </div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2005>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance of a piece of wire of length 20m and cross-sectional area 8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> is <br/>  <br/>  [ρ = 4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> Ωm]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0Ω</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Length, L = 20m; <br/> Cross sectional area, A = 8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-62</span>m;   <br/> Resistivity of the wire, ρ = 4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> Ωm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ρL<hr size=\"1\" />A</td><td style=\"text-align:center;\">-----------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> x 20<hr size=\"1\" />8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> R = 1.0Ω</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2005>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric device is rated 2000W, 250V.The correct fuse rating of the device is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fuse rating of an electric device is given by the formula: Fuse rating = Power / Voltage. Here, the power is 2000W and the voltage is 250V. So, Fuse rating = 2000 / 250 = 8A. Hence, the correct answer is 8A.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2005>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two charged particles are projected into a region where there is a magnetic field perpendicular to their velocities. <br/> If the charges are deflected in opposite directions, which of the following statements is true of the charges?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The charges are electrically neutral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The  charges  must  be  of  opposite signs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The charges are of the same sign</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Positive charges are more in number</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When two charged particles are projected into a magnetic field perpendicular to their velocities, they will be deflected in opposite directions if they carry charges of opposite signs. This is due to the Lorentz force law, which states that the force experienced by a charged particle in a magnetic field is proportional to the cross product of its velocity and the magnetic field. This force is also dependent on the sign of the charge, causing particles with different charges to be deflected in opposite directions.</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2005>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The North pole of a magnet can never be separated from the South pole because of a property known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnetic monopole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetic dipole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetic quadrupole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetic octopole</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The north pole of a magnet can never be separated from the South pole because of a property known as magnetic dipole.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2005>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A proton moving with a speed of 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>through a magnetic field of 1.0T experiences a magnetic force of magnitude  8.0  x  10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>N.  <br/> The angle between the proton's velocity and the field is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Speed, v = 1.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Magnetic field density, B = 1.0T <br/> Magnetic Force, F = 8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span> ; Charge, Q = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C <br/> Angle of Inclination, θ = ? <br/> Recall: <br/> F = BQVsinθ ---------------- * <br/> 8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span> = 1 × 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> × sinθ <br/> 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = sinθ <br/> sinθ = 0.5 <br/> θ = sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>(0.5) <br/> θ = 30°</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2005>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A transformer is rated 240V. If the primary coil is 4000 turns and the secondary voltage 12V, <br/>  Determine the number of turns in the secondary coil.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Primary voltage, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 240V <br/> Number of turns in the primary coil, N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 4000 turns  <br/> Secondary Voltage, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 12v <br/> Number of turns in the secondary coils, N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4000<hr size=\"1\" />N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">240<hr size=\"1\" />12</td></tr></table></div> <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 200 turns </div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>2005>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If two inductors of inductances 3H and 6H are arranged in series, the total inductance is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18.0H</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inductance is a property of an electrical conductor which opposes a change in current. When inductors are connected in series, the total inductance is the sum of the individual inductances. Therefore, the total inductance in this case is 3H + 6H = 9H.</div>", "topic": "ELECTROMAGNETIC INDUCTION : INDUCTANCE"}, {"id": "objective>Physics>2005>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an a.c. circuit that contains only a capacitor, the voltage lags behind the current by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a.c circuit that contains only a capacitor, i.e, a capacitive circuit, voltage lags behind current by 90°.</div>", "topic": "SIMPLE A. C. CIRCUITS : CAPACITOR - CAPACITIVE REACTANCE"}, {"id": "objective>Physics>2005>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The charge carriers in gases are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrons only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ions only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons and ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons and holes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In gases, both electrons and ions act as charge carriers. When a gas is ionized, it produces both negatively charged electrons and positively charged ions. These charged particles are then able to move and carry charge, making the gas conductive.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2005>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">235</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">92</span>U + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0</span>N <span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">144</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">56</span>Ba + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">90</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">36</span>Br + 2X  <br/>  <br/>  In the reaction above, X is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">proton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutrino</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">235</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">92</span>U + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0</span>N <span style=\"position:relative;left:-12px;top:-12px;\">&#8594</span> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">144</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">56</span>Ba + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">90</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">36</span>Br + 2X  <br/> Let X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>P <br/> So that we now have: <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">144</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">56</span>Ba + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">90</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">36</span>Kr + 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>P <br/> Equate the mass numbers and atomic numbers of both sides <br/> 23s + 1 = 144 + 90 + 2a ---------------- * <br/> 236 = 234 + 2a <br/> 2 = 2a <br/> a = 1 <br/> 92 + 0 = 56 + 36 + 2b <br/> 92 = 92 + 2b <br/> 0 = 2b <br/> b = 0 <br/> X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>P <br/> Neutron ( <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n )</div>", "topic": "ELEMENTARY MODERN PHYSICS : RADIOACTIVITY"}, {"id": "objective>Physics>2005>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of energy released when 0.5kg of uranium is burnt completely  <br/> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> mass(m) = 0.5kg <br/> speed of light, c = 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s <br/> Energy, E = ? <br/> Recall: E = Δmc<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> E = 0.5(3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> E = 0.5 × 9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span> <br/> E = 4.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span>J</div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}, {"id": "objective>Physics>2005>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In photoelectric effect, which of the following graphs correctly represents the graph stopping potential V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> against frequency,f, of incident light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2005/pis10.png\" style=\"position:relative;max-width:100%;\"/> <br/> At stopping potential the slope of V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> against F is zero.</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2005>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The time it will take a certain radioactive material with a half-life of 50 days to reduce to <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">32</span> of its original number is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150 days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200 days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250 days</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300 days</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> (half-life) = 50days <br/> Let the original size be x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">after</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">days</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">after</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">days</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">after</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">days</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />8</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">after</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">days</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />16</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">after</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">days</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />32</td></tr></table></div> <br/> ∴ It will reduce to 1/32 of the original size after (50 × 5)days or 250 days.</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2005>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ray which causes gas molecules to glow is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gamma ray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecular ray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cathode ray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anode ray</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cathode rays are streams of electrons observed in vacuum tubes. If a gas is present in the tube, the gas molecules can be excited by the electrons and emit light, causing the gas to glow. Therefore, the ray which causes gas molecules to glow is known as the cathode ray.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2005>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following materials is a conductor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wax</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A conductor is a material that allows the flow of electric charge. In other words, it conducts electricity. Sodium is a metal, and metals are good conductors of electricity because they have free electrons that can move easily. Therefore, Sodium is a conductor.</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2005>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A silicon material is dopped with an element of a certain group and an n-type semi-conductor is formed. The most likely group of the element is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An n-type semiconductor is formed when a silicon material is doped with an element from group V of the periodic table. These elements have five valence electrons, one of which can be donated to the silicon crystal, creating an extra electron which is free to move and carry current. Therefore, the correct answer is group V.</div>", "topic": "INTRODUCTORY ELECTRONICS : INTRINSIC AND EXTRINSIC SEMI-CONDUCTORS"}, {"id": "objective>Physics>2005>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When impurities are added to semi-conductors, the conductivity of the semi-conductor</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase then decreases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When impurities are added to semiconductors, a process known as doping, the conductivity of the semiconductor increases. This is because the impurities provide additional free charge carriers (either electrons or holes) that can carry current. Therefore, the correct answer is 'increases'.</div>", "topic": "INTRODUCTORY ELECTRONICS : INTRINSIC AND EXTRINSIC SEMI-CONDUCTORS"}, {"id": "objective>Physics>2005>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The current in a reverse-biased junction is due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">majority carriers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minority carriers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The current in reverse biased junction is due to minority carriers that is the negative charges in the R semi conductor  and positive charges in the semi conductor</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2005>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>   <br/> In the circuit  diagram of a transistor above, the terminals P, Q and represent</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">base, emitter and collector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">base, collector and emitter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emitter, base and collector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collector, emitter and base</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P, Q and R represent emitter, base and collector respectively.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}];
